(function(){"use strict";var V2="wgp_personal_best_v2";var V1="wgp_personal_best_v1";function digits(v){var n=parseInt(String(v==null?"":v).replace(/[^\d]/g,""),10);return n>0?n:0}function readV2(){try{return JSON.parse(localStorage.getItem(V2)||"null")||{}}catch(e){return{}}}function writeV2(map){try{localStorage.setItem(V2,JSON.stringify(map))}catch(e){}}function numericOf(entry){return entry&&entry.m?digits(entry.m.score||entry.m.highscore||""):0}function blankEntry(){return{m:{},note:"",date:null,name:"",url:"",img:""}}(function migrateV1(){try{var v1=JSON.parse(localStorage.getItem(V1)||"null");if(!v1||!v1.byHash)return;var map=readV2(),changed=false;Object.keys(v1.byHash).forEach(function(h){var s=digits(v1.byHash[h]&&v1.byHash[h].score);if(!s)return;var e=map[h];if(!e){e=blankEntry();e.m.score=String(s);map[h]=e;changed=true}else if(s>numericOf(e)){if(!e.m)e.m={};e.m.score=String(s);changed=true}});if(changed)writeV2(map);localStorage.removeItem(V1)}catch(e){}})();window.wgpScore={digits,get:function(hash){return readV2()[hash]||null},numeric:function(hash){return numericOf(readV2()[hash])},max:function(){var map=readV2(),m=0;Object.keys(map).forEach(function(h){var s=numericOf(map[h]);if(s>m)m=s});return m},set:function(hash,entry){if(!hash||!entry)return;var map=readV2();map[hash]=entry;writeV2(map)},bump:function(hash,metrics,note){if(!hash)return;var map=readV2();var e=map[hash]||blankEntry();if(!e.m)e.m={};metrics=metrics||{};Object.keys(metrics).forEach(function(k){if(k==="score"||k==="highscore"){var cur=digits(e.m[k]),inc=digits(metrics[k]);if(inc>=cur)e.m[k]=String(inc)}else{e.m[k]=metrics[k]}});if(note!=null&&note!=="")e.note=note;map[hash]=e;writeV2(map)},commit:function(hash,opts){if(!hash)return 0;opts=opts||{};if(opts.entry)this.set(hash,opts.entry);else this.bump(hash,opts.metrics||{},opts.note);var n=this.numeric(hash);if(opts.forCurrent&&n>0){try{if(window.wgpEngagement&&window.wgpEngagement.postPlaySession)window.wgpEngagement.postPlaySession(n)}catch(e2){}try{if(window.wgpRivals&&window.wgpRivals.setMyScore)window.wgpRivals.setMyScore(n)}catch(e2){}try{if(window.wgpChallengePlay&&window.wgpChallengePlay.reportScore)window.wgpChallengePlay.reportScore(n)}catch(e2){}}if(opts.pushServer!==false){try{var e=this.get(hash);var signedIn=window.wgpAuth&&window.wgpAuth.isSignedIn&&window.wgpAuth.isSignedIn();if(e&&e.m&&signedIn){fetch("/api/me/personal-best/save",{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/json"},body:JSON.stringify({hash,metrics:e.m,note:e.note||""})}).catch(function(){})}}catch(e2){}}return n},all:readV2}})();
